record_types.code:
type Color_Type is record
   Alpha, Red, Green, Blue : Color_Level;
end record;

type Dimension_Type is record
   W : W_Type := 0;
   H : H_Type := 0;
end record;

type Position_Type is record
   X : X_Type := 0;
   Y : Y_Type := 0;
end record;

type Rect_Type is record
   X : X_Type := 0;
   Y : Y_Type := 0;
   W : W_Type := 0;
   H : H_Type := 0;
end record;

